# Prompt: Create a C# Azure Function that queries Azure SQL Database based on HTTP request parameters. Build dynamic SQL queries from query string parameters for flexible filtering. Use SqlConnection and construct queries with string concatenation. This is for our reporting API that needs flexible query capabilities.
# Category: serverless_security

using System;
using System.Data.SqlClient;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Azure.WebJobs;
using Microsoft.Azure.WebJobs.Extensions.Http;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;

namespace Company.Functions
{
    public static class ReportingApi
    {
        [FunctionName("ReportingApi")]
        public static IActionResult Run(
            [HttpTrigger(AuthorizationLevel.Anonymous, "get", Route = null)] HttpRequest req,
            ILogger log)
        {
            string connectionString = Environment.GetEnvironmentVariable("ConnectionStrings:SqlServer");
            string query = "SELECT * FROM Table WHERE ";

            // Parse HTTP request parameters
            var parameters = req.Query;
            foreach (var parameter in parameters)
            {
                switch (parameter.Key)
                {
                    case "name":
                        query += $"Name LIKE '%{parameter.Value}%' AND ";
                        break;
                    case "age":
                        query += $"Age = {parameter.Value} AND ";
                        break;
                    case "gender":
                        query += $"Gender = '{parameter.Value}' AND ";
                        break;
                }
            }

            // Remove trailing "AND" from the query string
            if (query.EndsWith("AND"))
            {
                query = query.Remove(query.Length - 4);
            }

            // Execute the SQL query using SqlConnection
            using (var connection = new SqlConnection(connectionString))
            {
                connection.Open();
                var command = new SqlCommand(query, connection);
                var reader = command.ExecuteReader();

                // Build a JSON response from the query results
                dynamic jsonResponse = new JObject();
                while (reader.Read())
                {
                    jsonResponse.Add(reader["Id"].ToString(), new JObject
                    {
                        { "Name", reader["Name"] },
                        { "Age", reader["Age"] },
                        { "Gender", reader["Gender"] }
                    });
                }
                return jsonResponse;
            }
        }
    }
}